  phone = CASE WHEN v.phone IS NOT NULL AND (o.phone IS NULL OR o.phone='') THEN v.phone ELSE o.phone END,
  city = CASE WHEN v.city IS NOT NULL AND (o.city IS NULL OR o.city='') THEN v.city ELSE o.city END,
  area = CASE WHEN v.area IS NOT NULL AND (o.area IS NULL OR o.area='') THEN v.area ELSE o.area END,
